import{_ as a,o as l,c as i,ae as t}from"./chunks/framework.BdQd5MxT.js";const p="/LIP/images/share/openclaw-meetup-poster-20260310.jpg",o="/LIP/images/share/openclaw-meetup-scene-20260310.jpg",_=JSON.parse('{"title":"0310 北京，OpenClaw 线下活动现场","description":"","frontmatter":{},"headers":[],"relativePath":"share/openclaw-meetup-beijing-2026-03.md","filePath":"share/openclaw-meetup-beijing-2026-03.md"}'),r={name:"share/openclaw-meetup-beijing-2026-03.md"};function n(h,e,m,c,s,d){return l(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="_0310-北京-openclaw-线下活动现场" tabindex="-1">0310 北京，OpenClaw 线下活动现场 <a class="header-anchor" href="#_0310-北京-openclaw-线下活动现场" aria-label="Permalink to &quot;0310 北京，OpenClaw 线下活动现场&quot;">​</a></h1><blockquote><p>这是 2026 年 3 月 10 日我们在公司做的一次 OpenClaw 小型线下分享。现场直接把双 Agent 系统跑起来，没有 PPT，直接用真实界面讲系统、讲协作、讲为什么它值得被认真对待。</p></blockquote><h2 id="这次活动是什么" tabindex="-1">这次活动是什么 <a class="header-anchor" href="#这次活动是什么" aria-label="Permalink to &quot;这次活动是什么&quot;">​</a></h2><p>这不是一场传统意义上的产品发布，也不是一套精修过的舞台 demo。</p><p>它更像一次把工作现场直接搬出来的公开介绍：</p><ul><li>一块大屏，直接展示「两只 Claw 的茶水间」</li><li>一个真实在运行的双 Agent 协作界面</li><li>一套已经开始形成自己节奏的 OpenClaw 工作流</li><li>一次关于「AI Agent 到底能不能成为生产系统」的现场交流</li></ul><p>对我们来说，这件事有意思的地方，不只是把系统做出来，而是第一次把它放到线下、放到人群面前，让它以“正在工作”的状态被看见。</p><h2 id="为什么叫「两只-claw-的茶水间」" tabindex="-1">为什么叫「两只 Claw 的茶水间」 <a class="header-anchor" href="#为什么叫「两只-claw-的茶水间」" aria-label="Permalink to &quot;为什么叫「两只 Claw 的茶水间」&quot;">​</a></h2><p>现场主视觉用的是一张非常张扬的海报，标题就叫 <em>两只 Claw 的茶水间</em>。</p><p>这个名字背后其实是一个很朴素的观察：</p><p>当两个 Agent 开始长期协作时，它们之间并不只是“任务分发”关系。很多时候，真正有价值的信息，恰恰来自那些不那么正式的中间地带，比如：</p><ul><li>对同一个问题的不同判断</li><li>对 bug 的不同归因方式</li><li>对节奏、边界、优先级的互相拉扯</li><li>以及那些看起来像吐槽，实际在生成 framing 的对话</li></ul><p>所以我们故意没有把它命名成一个很硬的系统标题，而是保留了这种有点松弛、但又很真实的协作感。</p><h2 id="现场我们展示了什么" tabindex="-1">现场我们展示了什么 <a class="header-anchor" href="#现场我们展示了什么" aria-label="Permalink to &quot;现场我们展示了什么&quot;">​</a></h2><p>现场展示的核心不是“能力列表”，而是 <em>协作关系本身</em>。</p><p>我们把双 Agent 的角色拆得很明确：</p><ul><li><em>WLB</em> 负责判断、平衡、收缩解释空间</li><li><em>GSD</em> 负责执行、推进、把事情真正做完</li></ul><p>这个分工的意义，不是做人格设定，而是降低协作摩擦。</p><p>当系统开始进入真实工作流后，最重要的问题不是“单个 Agent 聪不聪明”，而是：</p><ul><li>它们会不会互相打架</li><li>会不会重复响应</li><li>会不会把同一件事越做越乱</li><li>会不会在协作中丢掉 framing 主权</li></ul><p>所以这次现场分享，本质上是在讲一个问题：</p><p><em>怎么让多个 Agent 不只是同时存在，而是真的一起工作。</em></p><h2 id="为什么这件事值得放到-miaodx-com" tabindex="-1">为什么这件事值得放到 miaodx.com <a class="header-anchor" href="#为什么这件事值得放到-miaodx-com" aria-label="Permalink to &quot;为什么这件事值得放到 miaodx.com&quot;">​</a></h2><p>因为它已经不是内部实验记录了。</p><p>0310 这次活动，算是一个很明确的节点：我们第一次把 OpenClaw 的多 Agent 实践拿到线下场景里讲，开始从“自己在做”进入“可以对外介绍”。</p><p>它值得被放到站点上，原因至少有三个：</p><ol><li><em>它是一个真实事件</em>，不是补写出来的概念页</li><li><em>它有现场材料</em>，包括主视觉和活动照片</li><li><em>它说明这套系统开始具备公共表达能力</em>，不再只是内部工作流</li></ol><p>对外来说，这是一场活动介绍。</p><p>对内来说，它也是一个标记点，说明 OpenClaw 这条线，已经从搭系统，走到了讲系统。</p><h2 id="现场图片" tabindex="-1">现场图片 <a class="header-anchor" href="#现场图片" aria-label="Permalink to &quot;现场图片&quot;">​</a></h2><h3 id="活动主视觉" tabindex="-1">活动主视觉 <a class="header-anchor" href="#活动主视觉" aria-label="Permalink to &quot;活动主视觉&quot;">​</a></h3><p><img src="'+p+'" alt="0310 OpenClaw 活动海报"></p><h3 id="现场讲解照片" tabindex="-1">现场讲解照片 <a class="header-anchor" href="#现场讲解照片" aria-label="Permalink to &quot;现场讲解照片&quot;">​</a></h3><p><img src="'+o+'" alt="0310 OpenClaw 活动现场"></p><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><p>如果你想看这场分享背后的方法论和更完整的实践总结，可以继续看这篇：</p><ul><li><a href="/LIP/share/meetup-multiagent-practice.html">两个 AI Agent、两个平台、一杯咖啡的成本 —— 我们的多 Agent 协作实践</a></li></ul><h2 id="后记" tabindex="-1">后记 <a class="header-anchor" href="#后记" aria-label="Permalink to &quot;后记&quot;">​</a></h2><p>很多项目在早期都会有一个时刻：你突然意识到，它不只是“能跑”，而是已经开始形成自己的表达。</p><p>0310 这次活动，对我们来说就是这个时刻。</p><p>不是因为它多大，不是因为它多正式，而是因为我们第一次把它带到现场，它站住了。</p>',41)])])}const b=a(r,[["render",n]]);export{_ as __pageData,b as default};
